window.onload=async()=>{for(var e of location.hash.slice(1).split("&"))e.startsWith("page=")&&e.split("page=")[1]&&showDetail(e.split("page=")[1])};const details={s0835:{ico:"s0835.png",name:"周家豪",tags:["英语课代表","朱朱朱朱蚝"],content:[[{type:"h6",attribute:{textContent:"个人简介："}},{type:"p",attribute:{textContent:"细柳营营长"}}]]}};function createElement(e){var t=document.createElement(e.type);if(e.attribute)for(var a of Object.keys(e.attribute))t[a]=e.attribute[a];if(e.class)for(var n of e.class)t.classList.add(n);if(e.chlidren)for(var o of e.chlidren)t.appendChild(createElement(o));return t}function showDetail(e){console.log("show detail",e),nowPage=e;var t=details[e];for(var a of(document.getElementById("ico").src="data/img/"+t.ico,document.getElementById("ico").onclick=()=>window.open("data/img/"+t.ico),document.getElementById("name").textContent=t.name,t.tags)){var n=document.createElement("tag");n.innerHTML=a,document.getElementById("tags").appendChild(n)}var o=t.content;for(var i of o){var l=document.createElement("div");for(var c of i)l.appendChild(createElement(c));l.classList.add("flex"),document.getElementById("details").appendChild(l)}}window.showDetail=showDetail;